class Solution {
    public int countSegments(String s) {
        if (s.trim().isEmpty()) {
            return 0;
        }
        int count = 1;
        for (int i = 0; i < s.length() - 1; i++) {
            if (s.charAt(i) == ' ' && s.charAt(i + 1) != ' ') {
                count++;
            }
        }
        return count;
    }
}
